// ===== COLUMN MAP — matches your sheet headers EXACTLY =====
// Sheet: forgeApp 15k automation n8n
// Columns: Timestamp | Email | Name | Edition | Payment | Product | Action | Status | Details
const COL = {
  email:        'Email',
  full_name:    'Name',
  product:      'Product',   // FFM | FC | FW | FAI
  payment:      'Payment',   // the column your team updates
  edition_name: 'Edition',   // e.g. 'Forge Filmmaking E18 Goa'
  // These columns are optional — add them to the sheet if you want finer control:
  phone:        'Phone',     // not required
  city:         'City',      // student's city
  edition_id:   '',          // leave blank — auto-resolved from edition name
  edition_city: '',          // leave blank — derived from edition name if possible
};
// ── Cohort type is AUTO-DERIVED from Product — no extra column needed ──
// FFM → FORGE | FC → FORGE_CREATORS | FW → FORGE_WRITING | FAI → FORGE_AI
const PRODUCT_COHORT = { FFM: 'FORGE', FC: 'FORGE_CREATORS', FW: 'FORGE_WRITING', FAI: 'FORGE_AI' };
// ── Payment column values — add your exact wording here ──
const BALANCE_PAID_VALUES  = ['balance paid', 'full paid', 'paid 50', '50000', 'completed', 'balance'];
const CONFIRMED_15K_VALUES = ['15k', 'deposit', 'confirmed', '15000', 'slot confirmed', 'advance'];
const DEFERRED_VALUES      = ['defer', 'waitlist', 'postpone', 'hold'];
// ============================================================

const body = $input.first().json.data ?? $input.first().json.body ?? $input.first().binary?.data ?? '';
const text = typeof body === 'string' ? body : '';

function parseCSV(t) {
  const rows = []; let row = [], cell = '', q = false;
  for (let i = 0; i < t.length; i++) {
    const c = t[i], n = t[i + 1];
    if (q) {
      if (c === '"' && n === '"') { cell += '"'; i++; }
      else if (c === '"') q = false;
      else cell += c;
    } else if (c === '"') q = true;
    else if (c === ',') { row.push(cell.trim()); cell = ''; }
    else if (c === '\n' || (c === '\r' && n === '\n')) { if (c === '\r') i++; row.push(cell.trim()); cell = ''; if (row.some(x => x !== '')) rows.push(row); row = []; }
    else cell += c;
  }
  if (cell || row.length) { row.push(cell.trim()); if (row.some(x => x !== '')) rows.push(row); }
  return rows;
}

const parsed = parseCSV(text);
if (parsed.length < 2) return [];
const headers = parsed[0];
const idx = (name) => name ? headers.findIndex(h => h.trim().toLowerCase() === name.trim().toLowerCase()) : -1;
const get = (r, name) => { const i = idx(name); return i >= 0 ? (r[i] || '') : ''; };
const norm = (s) => (s || '').toString().trim().toLowerCase();

const out = [];
for (let i = 1; i < parsed.length; i++) {
  const r = parsed[i];
  const email = norm(get(r, COL.email));
  if (!email || !email.includes('@')) continue;

  const payRaw = norm(get(r, COL.payment));
  let payment_status = null;
  if (BALANCE_PAID_VALUES.some(v => payRaw.includes(v)))       payment_status = 'BALANCE_PAID';
  else if (CONFIRMED_15K_VALUES.some(v => payRaw.includes(v))) payment_status = 'CONFIRMED_15K';
  else if (DEFERRED_VALUES.some(v => payRaw.includes(v)))      payment_status = 'DEFERRED';
  if (!payment_status) continue;

  const product = (get(r, COL.product) || 'FFM').trim().toUpperCase();
  // Auto-derive cohort_type from product — no Cohort Type column needed in sheet
  const cohort_type = PRODUCT_COHORT[product] || 'FORGE';

  const json = {
    student_id:   email,
    email,
    full_name:    get(r, COL.full_name),
    phone:        get(r, COL.phone) || undefined,
    city:         get(r, COL.city)  || undefined,
    product,
    payment_status,
    edition_id:   get(r, COL.edition_id)   || undefined,
    edition_name: get(r, COL.edition_name) || undefined,
    edition_city: get(r, COL.edition_city) || undefined,
    cohort_type,  // always set — derived from product
  };
  json._onboardable = payment_status === 'CONFIRMED_15K' || payment_status === 'BALANCE_PAID';
  out.push({ json });
}
return out;

// Build a clean log row combining the original student data + onboarding API response.
return $input.all().map(item => {
  const resp = item.json;           // response from forge-onboard-student
  const orig = $('Onboardable?').item.json;  // original student data
  return {
    json: {
      'Timestamp':  new Date().toISOString().replace('T', ' ').slice(0, 19),
      'Email':      orig.email      || '',
      'Name':       orig.full_name  || '',
      'Edition':    orig.edition_name || orig.edition_id || '',
      'Payment':    orig.payment_status || '',
      'Product':    orig.product    || '',
      'Action':     'Onboarding',
      'Status':     resp.status     || 'unknown',
      'Details':    resp.message    || resp.error || JSON.stringify(resp).slice(0, 300)
    }
  };
});

for (const item of $input.all()) {
  console.warn('[forge-onboard] FAILED for', item.json.Email, '→', item.json.Status, ':', item.json.Details);
}
return $input.all();

// Build a clean log row for payment sync events.
return $input.all().map(item => {
  const orig = $('Parse & Classify Rows').item.json;
  return {
    json: {
      'Timestamp':  new Date().toISOString().replace('T', ' ').slice(0, 19),
      'Email':      orig.email         || '',
      'Name':       orig.full_name     || '',
      'Edition':    orig.edition_name  || '',
      'Payment':    orig.payment_status || '',
      'Product':    orig.product       || '',
      'Action':     'Payment Sync',
      'Status':     'synced',
      'Details':    `${orig.payment_status} → unlock_level: ${orig.payment_status === 'BALANCE_PAID' ? 'FULL' : 'PREVIEW'}`
    }
  };
});
